"use client"

import { useState, useRef, useEffect, useCallback, Suspense } from "react"
import { useSearchParams, useRouter } from "next/navigation"
import {
  ImageIcon, Type, Download, Trash2, ZoomIn, ZoomOut, Grid3x3,
  Undo2, Redo2, Eye, EyeOff, AlignLeft, AlignCenter, AlignRight,
  Sparkles, RefreshCw, Layers, Move, ChevronUp, ChevronDown, Lock
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Slider } from "@/components/ui/slider"
import { useToast } from "@/hooks/use-toast"
import { Badge } from "@/components/ui/badge"
import { Separator } from "@/components/ui/separator"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { ScrollArea } from "@/components/ui/scroll-area"

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000"

// ─── Types ─────────────────────────────────────────────────────────────────
interface Layer {
  layer_id: string
  type: "image" | "text"
  x: number; y: number
  width?: number; height?: number
  rotation: number; opacity: number
  file_id?: string
  text?: string; font_size?: number; color?: string
  font_family?: string; font_weight?: string; text_align?: string
  visible?: boolean; locked?: boolean
}
interface Project {
  _id: string; width: number; height: number
  background_color: string; layers: Layer[]
}
type HandlePos = "tl"|"tc"|"tr"|"ml"|"mr"|"bl"|"bc"|"br"

const CANVAS_SIZES = [
  { label: "Instagram Square", value: "1080x1080" },
  { label: "Instagram Portrait", value: "1080x1350" },
  { label: "Instagram Story", value: "1080x1920" },
  { label: "Facebook Banner", value: "1200x628" },
  { label: "YouTube Thumbnail", value: "1280x720" },
  { label: "Display Ad", value: "728x90" },
]
const FONT_FAMILIES = ["Arial","Georgia","Courier New","Verdana","Times New Roman","Impact"]

// ─── Handle positions on a bounding box ────────────────────────────────────
const HANDLES: { id: HandlePos; cx: number; cy: number; cursor: string }[] = [
  { id:"tl", cx:0,   cy:0,   cursor:"nw-resize" },
  { id:"tc", cx:0.5, cy:0,   cursor:"n-resize"  },
  { id:"tr", cx:1,   cy:0,   cursor:"ne-resize" },
  { id:"ml", cx:0,   cy:0.5, cursor:"w-resize"  },
  { id:"mr", cx:1,   cy:0.5, cursor:"e-resize"  },
  { id:"bl", cx:0,   cy:1,   cursor:"sw-resize" },
  { id:"bc", cx:0.5, cy:1,   cursor:"s-resize"  },
  { id:"br", cx:1,   cy:1,   cursor:"se-resize" },
]

function EditorInner() {
  const searchParams = useSearchParams()
  const router = useRouter()
  const { toast } = useToast()

  const [project, setProject] = useState<Project | null>(null)
  const [projectName, setProjectName] = useState("Untitled Project")
  const [showNameDialog, setShowNameDialog] = useState(false)
  const [canvasSize, setCanvasSize] = useState({ width: 1080, height: 1080 })
  const [bgColor, setBgColor] = useState("#FFFFFF")
  const [zoom, setZoom] = useState(0.5)
  const [showGrid, setShowGrid] = useState(false)
  const [loading, setLoading] = useState(false)

  // Selection & editing
  const [selectedId, setSelectedId] = useState<string | null>(null)
  const [editingTextId, setEditingTextId] = useState<string | null>(null)
  const [inlineText, setInlineText] = useState("")

  // Drag state
  const [dragState, setDragState] = useState<{
    layerId: string; startMX: number; startMY: number
    origX: number; origY: number
  } | null>(null)

  // Resize state
  const [resizeState, setResizeState] = useState<{
    layerId: string; handle: HandlePos
    startMX: number; startMY: number
    origX: number; origY: number; origW: number; origH: number
  } | null>(null)

  // AI
  const [showAiPanel, setShowAiPanel] = useState(false)
  const [aiProduct, setAiProduct] = useState("")
  const [aiLoading, setAiLoading] = useState(false)
  const [aiVariants, setAiVariants] = useState<any[]>([])

  const fileInputRef = useRef<HTMLInputElement>(null)
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  const selectedLayer = project?.layers.find(l => l.layer_id === selectedId) ?? null

  // ── API helper ────────────────────────────────────────────────────────────
  const api = async (endpoint: string, opts: RequestInit = {}) => {
    const res = await fetch(`${API_BASE}${endpoint}`, opts)
    if (!res.ok) {
      const err = await res.json().catch(() => ({ detail: "Request failed" }))
      throw new Error(err.detail || `HTTP ${res.status}`)
    }
    return res.json()
  }

  // ── Boot: load existing or show create dialog ─────────────────────────────
  useEffect(() => {
    const pid = searchParams?.get("project")
    if (pid) {
      loadExistingProject(pid)
    } else {
      setShowNameDialog(true)
    }
  }, [])

  const loadExistingProject = async (pid: string) => {
    setLoading(true)
    try {
      const data = await api(`/editor/${pid}`)
      setProject(data)
      setProjectName(data.name || "Untitled Project")
      setCanvasSize({ width: data.width, height: data.height })
      setBgColor(data.background_color || "#FFFFFF")
    } catch (e: any) {
      toast({ title: "Could not load project", description: e.message, variant: "destructive" })
      setShowNameDialog(true)
    } finally {
      setLoading(false)
    }
  }

  const initProject = async (name: string) => {
    setLoading(true)
    try {
      const params = new URLSearchParams({
        width: String(canvasSize.width), height: String(canvasSize.height),
        background_color: bgColor, name
      })
      const res = await api(`/editor/create-project?${params}`, { method: "POST" })
      const data = await api(`/editor/${res.project_id}`)
      setProject(data)
      setProjectName(name)
      router.replace(`/editor?project=${res.project_id}`)
      toast({ title: "Project Created", description: `"${name}" is ready` })
    } catch (e: any) {
      toast({ title: "Error", description: e.message, variant: "destructive" })
    } finally {
      setLoading(false)
    }
  }

  const refreshProject = async () => {
    if (!project) return
    const updated = await api(`/editor/${project._id}`)
    setProject(updated)
    // keep selection synced
    if (selectedId) {
      const still = updated.layers.find((l: Layer) => l.layer_id === selectedId)
      if (!still) setSelectedId(null)
    }
  }

  // ── Layer ops ─────────────────────────────────────────────────────────────
  const addImage = async (file: File) => {
    if (!project) return
    setLoading(true)
    try {
      const fd = new FormData()
      fd.append("file", file)
      fd.append("x", "50"); fd.append("y", "50")
      fd.append("width", String(Math.min(400, canvasSize.width - 100)))
      fd.append("height", String(Math.min(400, canvasSize.height - 100)))
      await api(`/editor/${project._id}/add-image-layer`, { method:"POST", body:fd })
      await refreshProject()
      toast({ title: "Image Added" })
    } catch (e: any) {
      toast({ title: "Error", description: e.message, variant: "destructive" })
    } finally { setLoading(false) }
  }

  const addText = async () => {
    if (!project) return
    setLoading(true)
    try {
      const params = new URLSearchParams({ text:"Double-click to edit", font_size:"48", color:"#000000", x:"100", y:"100" })
      await api(`/editor/${project._id}/add-text-layer?${params}`, { method:"POST" })
      await refreshProject()
      toast({ title: "Text Added" })
    } catch (e: any) {
      toast({ title: "Error", description: e.message, variant: "destructive" })
    } finally { setLoading(false) }
  }

  const updateLayer = useCallback(async (layerId: string, updates: Partial<Layer>) => {
    if (!project) return
    // Optimistic update
    setProject(p => p ? { ...p, layers: p.layers.map(l => l.layer_id === layerId ? {...l, ...updates} : l) } : p)
    try {
      await api(`/editor/${project._id}/update-layer/${layerId}`, {
        method: "PUT", headers: { "Content-Type": "application/json" }, body: JSON.stringify(updates)
      })
    } catch { await refreshProject() }
  }, [project])

  const deleteLayer = async (layerId: string) => {
    if (!project) return
    try {
      await api(`/editor/${project._id}/layer/${layerId}`, { method:"DELETE" })
      setSelectedId(null)
      await refreshProject()
    } catch (e: any) { toast({ title: "Delete failed", description: e.message, variant: "destructive" }) }
  }

  const handleUndo = async () => {
    if (!project) return
    try {
      await api(`/editor/${project._id}/undo`, { method:"POST" })
      await refreshProject()
      toast({ title: "Undone ↩" })
    } catch { toast({ title: "Nothing to undo" }) }
  }

  const handleRedo = async () => {
    if (!project) return
    try {
      await api(`/editor/${project._id}/redo`, { method:"POST" })
      await refreshProject()
      toast({ title: "Redone ↪" })
    } catch { toast({ title: "Nothing to redo" }) }
  }

  const exportPNG = async () => {
    if (!project) return
    setLoading(true)
    try {
      const res = await api(`/editor/${project._id}/render`)
      const a = document.createElement("a")
      a.href = `${API_BASE}/editor/rendered/${res.rendered_file_id}/download`
      a.download = `${projectName}.png`
      a.click()
      toast({ title: "Export Complete" })
    } catch (e: any) {
      toast({ title: "Export failed", description: e.message, variant: "destructive" })
    } finally { setLoading(false) }
  }

  // ── Drag handlers ─────────────────────────────────────────────────────────
  const onLayerMouseDown = (e: React.MouseEvent, layer: Layer) => {
    if (layer.locked || editingTextId) return
    e.stopPropagation()
    // Single click selects; drag begins immediately (mouse-move threshold handled in onMove)
    setSelectedId(layer.layer_id)
    setDragState({
      layerId: layer.layer_id,
      startMX: e.clientX, startMY: e.clientY,
      origX: layer.x, origY: layer.y
    })
  }

  const onResizeHandleMouseDown = (e: React.MouseEvent, layer: Layer, handle: HandlePos) => {
    e.stopPropagation()
    setResizeState({
      layerId: layer.layer_id, handle,
      startMX: e.clientX, startMY: e.clientY,
      origX: layer.x, origY: layer.y,
      origW: layer.width || 200, origH: layer.height || 200
    })
  }

  const onCanvasMouseMove = (e: React.MouseEvent) => {
    if (dragState) {
      const dx = (e.clientX - dragState.startMX) / zoom
      const dy = (e.clientY - dragState.startMY) / zoom
      if (Math.abs(dx) < 1 && Math.abs(dy) < 1) return
      const newX = Math.round(dragState.origX + dx)
      const newY = Math.round(dragState.origY + dy)
      setProject(p => p ? {
        ...p, layers: p.layers.map(l =>
          l.layer_id === dragState.layerId ? { ...l, x: newX, y: newY } : l
        )
      } : p)
    } else if (resizeState) {
      const dx = (e.clientX - resizeState.startMX) / zoom
      const dy = (e.clientY - resizeState.startMY) / zoom
      let { origX: x, origY: y, origW: w, origH: h } = resizeState
      const h2 = resizeState.handle
      if (h2.includes("r")) w = Math.max(20, resizeState.origW + dx)
      if (h2.includes("l")) { w = Math.max(20, resizeState.origW - dx); x = resizeState.origX + dx }
      if (h2.includes("b")) h = Math.max(20, resizeState.origH + dy)
      if (h2.includes("t")) { h = Math.max(20, resizeState.origH - dy); y = resizeState.origY + dy }
      setProject(p => p ? {
        ...p, layers: p.layers.map(l =>
          l.layer_id === resizeState.layerId
            ? { ...l, x: Math.round(x), y: Math.round(y), width: Math.round(w), height: Math.round(h) }
            : l
        )
      } : p)
    }
  }

  const onCanvasMouseUp = async () => {
    if (dragState) {
      const layer = project?.layers.find(l => l.layer_id === dragState.layerId)
      if (layer && (layer.x !== dragState.origX || layer.y !== dragState.origY)) {
        await updateLayer(dragState.layerId, { x: layer.x, y: layer.y })
      }
      setDragState(null)
    }
    if (resizeState) {
      const layer = project?.layers.find(l => l.layer_id === resizeState.layerId)
      if (layer) {
        await updateLayer(resizeState.layerId, { x: layer.x, y: layer.y, width: layer.width, height: layer.height })
      }
      setResizeState(null)
    }
  }

  // Double-click on text → enter inline edit mode
  const onLayerDoubleClick = (e: React.MouseEvent, layer: Layer) => {
    e.stopPropagation()
    if (layer.type === "text") {
      setEditingTextId(layer.layer_id)
      setInlineText(layer.text || "")
      setTimeout(() => textareaRef.current?.focus(), 50)
    }
  }

  const commitTextEdit = async () => {
    if (!editingTextId) return
    await updateLayer(editingTextId, { text: inlineText })
    setEditingTextId(null)
  }

  // ── AI Copy ───────────────────────────────────────────────────────────────
  const fetchAI = async () => {
    if (!aiProduct.trim()) return
    setAiLoading(true)
    try {
      const res = await api("/ai/copy-suggestions", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ product_name: aiProduct, platform:"instagram", tone:"professional", num_variants:3 })
      })
      setAiVariants(res.variants || [])
    } catch (e: any) {
      toast({ title:"AI Error", description: e.message + " — ensure Mistral key is set", variant:"destructive" })
    } finally { setAiLoading(false) }
  }

  const applyAIVariant = async (v: any) => {
    if (!project) return
    const p1 = new URLSearchParams({ text: v.headline, font_size:"64", color:"#FFFFFF", x:"80", y:"80" })
    await api(`/editor/${project._id}/add-text-layer?${p1}`, { method:"POST" })
    const p2 = new URLSearchParams({ text: v.cta, font_size:"40", color:"#E94560", x:"80", y:"160" })
    await api(`/editor/${project._id}/add-text-layer?${p2}`, { method:"POST" })
    await refreshProject()
    toast({ title:"AI Copy Applied" })
  }

  // ── Render helpers ────────────────────────────────────────────────────────
  const getLayerStyle = (layer: Layer): React.CSSProperties => ({
    position: "absolute",
    left: `${layer.x * zoom}px`,
    top: `${layer.y * zoom}px`,
    width: layer.width ? `${layer.width * zoom}px` : undefined,
    height: layer.height ? `${layer.height * zoom}px` : undefined,
    transform: `rotate(${layer.rotation}deg)`,
    opacity: layer.opacity ?? 1,
    display: layer.visible === false ? "none" : undefined,
    cursor: layer.locked ? "not-allowed" : "move",
    userSelect: "none",
    boxSizing: "border-box",
  })

  const renderHandles = (layer: Layer) => {
    const w = (layer.width || 200) * zoom
    const h = (layer.height || 60) * zoom
    return HANDLES.map(hd => (
      <div
        key={hd.id}
        onMouseDown={e => { e.stopPropagation(); onResizeHandleMouseDown(e, layer, hd.id) }}
        style={{
          position: "absolute",
          left: `${hd.cx * w - 5}px`,
          top: `${hd.cy * h - 5}px`,
          width: 10, height: 10,
          background: "#6366f1",
          border: "2px solid #fff",
          borderRadius: 2,
          cursor: hd.cursor,
          zIndex: 100,
          boxShadow: "0 1px 3px rgba(0,0,0,0.4)"
        }}
      />
    ))
  }

  const renderLayer = (layer: Layer) => {
    const isSelected = selectedId === layer.layer_id
    const isEditingThis = editingTextId === layer.layer_id

    return (
      <div
        key={layer.layer_id}
        style={getLayerStyle(layer)}
        onMouseDown={e => onLayerMouseDown(e, layer)}
        onDoubleClick={e => onLayerDoubleClick(e, layer)}
        onClick={e => { e.stopPropagation(); setSelectedId(layer.layer_id) }}
      >
        {/* Border outline */}
        {isSelected && (
          <div style={{
            position:"absolute", inset:-2, border:"2px solid #6366f1",
            pointerEvents:"none", zIndex:50,
            boxShadow:"0 0 0 1px rgba(99,102,241,0.3)"
          }} />
        )}

        {/* Resize handles */}
        {isSelected && !layer.locked && !isEditingThis && renderHandles(layer)}

        {/* Image content */}
        {layer.type === "image" && layer.file_id && (
          // eslint-disable-next-line @next/next/no-img-element
          <img
            src={`${API_BASE}/asset/${layer.file_id}`}
            alt="layer"
            draggable={false}
            crossOrigin="anonymous"
            style={{ width:"100%", height:"100%", objectFit:"cover", display:"block", pointerEvents:"none" }}
            onError={e => { (e.currentTarget as HTMLImageElement).style.opacity = "0.3" }}
          />
        )}

        {/* Text content — normal display */}
        {layer.type === "text" && !isEditingThis && (
          <div style={{
            fontSize: `${(layer.font_size || 48) * zoom}px`,
            color: layer.color || "#000000",
            fontFamily: layer.font_family || "Arial",
            fontWeight: (layer.font_weight as any) || "bold",
            textAlign: (layer.text_align as any) || "left",
            whiteSpace: "pre-wrap",
            lineHeight: 1.2,
            pointerEvents: "none",
            minWidth: "50px",
            minHeight: "30px",
          }}>
            {layer.text || "Text"}
          </div>
        )}

        {/* Inline text editor */}
        {layer.type === "text" && isEditingThis && (
          <textarea
            ref={textareaRef}
            value={inlineText}
            onChange={e => setInlineText(e.target.value)}
            onBlur={commitTextEdit}
            onKeyDown={e => { if (e.key === "Escape") commitTextEdit() }}
            style={{
              fontSize: `${(layer.font_size || 48) * zoom}px`,
              color: layer.color || "#000000",
              fontFamily: layer.font_family || "Arial",
              fontWeight: (layer.font_weight as any) || "bold",
              textAlign: (layer.text_align as any) || "left",
              lineHeight: 1.2,
              border: "2px dashed #6366f1",
              outline: "none",
              background: "rgba(255,255,255,0.15)",
              resize: "none",
              width: layer.width ? `${layer.width * zoom}px` : "300px",
              minHeight: "40px",
              padding: "2px 4px",
              zIndex: 200,
              position: "relative",
              cursor: "text",
            }}
          />
        )}
      </div>
    )
  }

  // ── Sidebar props panel ───────────────────────────────────────────────────
  const PropsPanel = () => {
    if (!selectedLayer) return (
      <div className="text-center py-8 text-muted-foreground text-xs px-3">
        <Move className="h-8 w-8 mx-auto mb-2 opacity-30" />
        <p>Click a layer to select</p>
        <p className="mt-1 opacity-60">Double-click text to edit</p>
      </div>
    )
    const l = selectedLayer
    return (
      <div className="p-3 space-y-3">
        <div className="flex items-center justify-between">
          <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Properties</p>
          <Button size="sm" variant="ghost" className="h-6 w-6 p-0 text-destructive" onClick={() => deleteLayer(l.layer_id)}>
            <Trash2 className="h-3 w-3" />
          </Button>
        </div>

        {/* Position */}
        <div className="grid grid-cols-2 gap-1.5">
          {(["x","y"] as const).map(k => (
            <div key={k} className="space-y-1">
              <Label className="text-xs uppercase">{k}</Label>
              <Input type="number" className="h-8 text-xs" value={l[k]}
                onChange={e => updateLayer(l.layer_id, { [k]: +e.target.value || 0 })} />
            </div>
          ))}
        </div>

        {/* Size (image only) */}
        {l.type === "image" && (
          <div className="grid grid-cols-2 gap-1.5">
            {(["width","height"] as const).map(k => (
              <div key={k} className="space-y-1">
                <Label className="text-xs uppercase">{k === "width" ? "W" : "H"}</Label>
                <Input type="number" className="h-8 text-xs" value={l[k] || 0}
                  onChange={e => updateLayer(l.layer_id, { [k]: +e.target.value || 0 })} />
              </div>
            ))}
          </div>
        )}

        {/* Text props */}
        {l.type === "text" && (
          <div className="space-y-2">
            <div className="space-y-1">
              <Label className="text-xs">Text — double-click canvas to edit inline</Label>
              <textarea rows={2} className="w-full text-xs border border-input rounded p-1.5 bg-background resize-none"
                value={l.text || ""} onChange={e => updateLayer(l.layer_id, { text: e.target.value })} />
            </div>
            <div className="space-y-1">
              <Label className="text-xs">Font Size</Label>
              <Input type="number" className="h-8 text-xs" value={l.font_size || 48}
                onChange={e => updateLayer(l.layer_id, { font_size: +e.target.value || 12 })} />
            </div>
            <div className="space-y-1">
              <Label className="text-xs">Font Family</Label>
              <Select value={l.font_family || "Arial"} onValueChange={v => updateLayer(l.layer_id, { font_family: v })}>
                <SelectTrigger className="h-8 text-xs"><SelectValue /></SelectTrigger>
                <SelectContent>{FONT_FAMILIES.map(f => <SelectItem key={f} value={f}>{f}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div className="space-y-1">
              <Label className="text-xs">Color</Label>
              <div className="flex gap-1.5">
                <input type="color" value={l.color || "#000000"} className="w-10 h-8 rounded border cursor-pointer"
                  onChange={e => updateLayer(l.layer_id, { color: e.target.value })} />
                <Input value={l.color || "#000000"} className="h-8 text-xs flex-1"
                  onChange={e => updateLayer(l.layer_id, { color: e.target.value })} />
              </div>
            </div>
            <div className="flex gap-1">
              {(["left","center","right"] as const).map(a => (
                <Button key={a} size="sm" variant={l.text_align === a ? "secondary" : "ghost"} className="h-7 flex-1 p-0"
                  onClick={() => updateLayer(l.layer_id, { text_align: a })}>
                  {a === "left" ? <AlignLeft className="h-3 w-3" /> : a === "center" ? <AlignCenter className="h-3 w-3" /> : <AlignRight className="h-3 w-3" />}
                </Button>
              ))}
            </div>
          </div>
        )}

        {/* Rotation & Opacity */}
        <div className="space-y-1">
          <Label className="text-xs">Rotation ({l.rotation}°)</Label>
          <Slider value={[l.rotation]} onValueChange={([v]) => updateLayer(l.layer_id, { rotation: v })} min={-180} max={180} step={1} />
        </div>
        <div className="space-y-1">
          <Label className="text-xs">Opacity ({Math.round((l.opacity ?? 1) * 100)}%)</Label>
          <Slider value={[(l.opacity ?? 1) * 100]} onValueChange={([v]) => updateLayer(l.layer_id, { opacity: v / 100 })} min={0} max={100} step={1} />
        </div>
      </div>
    )
  }

  // ── Main render ───────────────────────────────────────────────────────────
  return (
    <>
      {/* Create dialog */}
      <Dialog open={showNameDialog} onOpenChange={setShowNameDialog}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Create New Project</DialogTitle>
            <DialogDescription>Name your canvas and set its size</DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1">
              <Label>Project Name</Label>
              <Input placeholder="e.g., Summer Sale Campaign" value={projectName}
                onChange={e => setProjectName(e.target.value)}
                onKeyDown={e => { if (e.key === "Enter" && projectName.trim()) { setShowNameDialog(false); initProject(projectName.trim()) }}} />
            </div>
            <div className="space-y-1">
              <Label>Canvas Size</Label>
              <Select value={`${canvasSize.width}x${canvasSize.height}`}
                onValueChange={v => { const [w,h] = v.split("x").map(Number); setCanvasSize({width:w,height:h}) }}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{CANVAS_SIZES.map(s => <SelectItem key={s.value} value={s.value}>{s.label} ({s.value})</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div className="space-y-1">
              <Label>Background Color</Label>
              <div className="flex gap-2">
                <input type="color" value={bgColor} onChange={e => setBgColor(e.target.value)} className="w-12 h-10 rounded border cursor-pointer" />
                <Input value={bgColor} onChange={e => setBgColor(e.target.value)} />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button className="w-full gradient-primary" disabled={!projectName.trim()}
              onClick={() => { setShowNameDialog(false); initProject(projectName.trim()) }}>
              Create Project
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <div className="flex h-full overflow-hidden">
        {/* ── Left Sidebar ──────────────────────────────────────────── */}
        <div className="w-64 shrink-0 border-r border-border bg-card flex flex-col overflow-hidden">
          <div className="p-3 border-b border-border space-y-1.5">
            <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-2">Elements</p>
            <input ref={fileInputRef} type="file" accept="image/*" className="hidden"
              onChange={e => { if (e.target.files?.[0]) addImage(e.target.files[0]); e.target.value = "" }} />
            <Button className="w-full gap-2 gradient-primary h-9" onClick={() => fileInputRef.current?.click()} disabled={!project || loading}>
              <ImageIcon className="h-4 w-4" /> Add Image
            </Button>
            <Button className="w-full gap-2 h-9 bg-transparent" variant="outline" onClick={addText} disabled={!project || loading}>
              <Type className="h-4 w-4" /> Add Text
            </Button>
            <Button className="w-full gap-2 h-9 bg-transparent" variant="outline" onClick={() => setShowAiPanel(v=>!v)} disabled={!project}>
              <Sparkles className="h-4 w-4 text-yellow-500" /> AI Copy
            </Button>
          </div>

          {/* AI Panel */}
          {showAiPanel && (
            <div className="p-3 border-b border-border bg-accent/5 space-y-2">
              <p className="text-xs font-semibold">AI Copy Generator</p>
              <Input placeholder="Product name..." value={aiProduct} onChange={e => setAiProduct(e.target.value)} className="h-8 text-sm" />
              <Button size="sm" className="w-full gradient-primary h-8" onClick={fetchAI} disabled={aiLoading || !aiProduct.trim()}>
                {aiLoading ? <RefreshCw className="h-3 w-3 animate-spin mr-1" /> : <Sparkles className="h-3 w-3 mr-1" />}
                Generate
              </Button>
              {aiVariants.map((v,i) => (
                <div key={i} className="rounded border border-border p-2 text-xs space-y-1 bg-background">
                  <p className="font-bold">{v.headline}</p>
                  <p className="text-muted-foreground text-[10px]">{v.subheadline}</p>
                  <Badge variant="secondary" className="text-[10px]">{v.cta}</Badge>
                  <Button size="sm" variant="ghost" className="w-full h-6 text-xs" onClick={() => applyAIVariant(v)}>Apply →</Button>
                </div>
              ))}
            </div>
          )}

          {/* Properties */}
          <ScrollArea className="flex-1">
            <PropsPanel />
          </ScrollArea>

          {/* Actions */}
          <div className="p-3 border-t border-border space-y-1.5">
            <div className="flex gap-1">
              <Button className="flex-1 h-8 bg-transparent gap-1 text-xs" variant="outline" onClick={handleUndo} disabled={!project}>
                <Undo2 className="h-3 w-3" />Undo
              </Button>
              <Button className="flex-1 h-8 bg-transparent gap-1 text-xs" variant="outline" onClick={handleRedo} disabled={!project}>
                <Redo2 className="h-3 w-3" />Redo
              </Button>
            </div>
            <Button className="w-full h-9 gradient-primary gap-2" onClick={exportPNG} disabled={!project || loading}>
              <Download className="h-4 w-4" />{loading ? "Rendering..." : "Export PNG"}
            </Button>
          </div>
        </div>

        {/* ── Canvas Area ───────────────────────────────────────────── */}
        <div className="flex-1 flex flex-col min-w-0">
          {/* Toolbar */}
          <div className="border-b border-border bg-card px-4 py-2 flex items-center gap-2 flex-wrap">
            {project && <Badge variant="secondary" className="text-xs max-w-[180px] truncate">{projectName}</Badge>}
            <Separator orientation="vertical" className="h-5" />
            <Select value={`${canvasSize.width}x${canvasSize.height}`}
              onValueChange={v => { const [w,h] = v.split("x").map(Number); setCanvasSize({width:w,height:h}) }}>
              <SelectTrigger className="w-40 h-8 text-xs"><SelectValue /></SelectTrigger>
              <SelectContent>{CANVAS_SIZES.map(s => <SelectItem key={s.value} value={s.value}>{s.label}</SelectItem>)}</SelectContent>
            </Select>
            <Separator orientation="vertical" className="h-5" />
            <Button variant="ghost" size="sm" className="h-8 w-8 p-0" onClick={() => setZoom(z => Math.max(0.1, +(z-0.1).toFixed(1)))}>
              <ZoomOut className="h-4 w-4" />
            </Button>
            <span className="text-xs w-10 text-center font-mono">{Math.round(zoom*100)}%</span>
            <Button variant="ghost" size="sm" className="h-8 w-8 p-0" onClick={() => setZoom(z => Math.min(2, +(z+0.1).toFixed(1)))}>
              <ZoomIn className="h-4 w-4" />
            </Button>
            <Button variant="ghost" size="sm" className="h-8 w-8 p-0" onClick={() => setShowGrid(v=>!v)}>
              <Grid3x3 className={`h-4 w-4 ${showGrid ? "text-primary" : ""}`} />
            </Button>
            {editingTextId && (
              <Badge className="bg-primary/20 text-primary text-xs">✏️ Editing text — click outside to finish</Badge>
            )}
          </div>

          {/* Canvas + Layer panel */}
          <div className="flex flex-1 min-h-0">
            {/* Canvas workspace */}
            <div
              className="flex-1 overflow-auto bg-muted/30 flex items-start justify-center p-8"
              style={{ cursor: dragState || resizeState ? "grabbing" : "default" }}
              onMouseMove={onCanvasMouseMove}
              onMouseUp={onCanvasMouseUp}
              onMouseLeave={onCanvasMouseUp}
            >
              {!project ? (
                <div className="flex items-center justify-center h-full w-full text-muted-foreground">
                  <div className="text-center">
                    <Layers className="h-16 w-16 mx-auto mb-4 opacity-20" />
                    <p>Enter a project name to start designing</p>
                  </div>
                </div>
              ) : (
                <div
                  className="relative shadow-2xl flex-shrink-0"
                  style={{
                    width: `${canvasSize.width * zoom}px`,
                    height: `${canvasSize.height * zoom}px`,
                    backgroundColor: project.background_color || "#FFFFFF",
                    backgroundImage: showGrid
                      ? `repeating-linear-gradient(0deg,#e5e7eb 0,#e5e7eb 1px,transparent 1px,transparent ${20*zoom}px),repeating-linear-gradient(90deg,#e5e7eb 0,#e5e7eb 1px,transparent 1px,transparent ${20*zoom}px)`
                      : undefined,
                  }}
                  onClick={e => {
                    if (e.target === e.currentTarget) {
                      setSelectedId(null)
                      if (editingTextId) commitTextEdit()
                    }
                  }}
                >
                  {project.layers.map(renderLayer)}
                </div>
              )}
            </div>

            {/* Layer panel */}
            {project && (
              <div className="w-48 shrink-0 border-l border-border bg-card flex flex-col">
                <div className="p-3 border-b border-border">
                  <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider flex items-center gap-1">
                    <Layers className="h-3 w-3" /> Layers ({project.layers.length})
                  </p>
                </div>
                <ScrollArea className="flex-1">
                  <div className="p-2 space-y-1">
                    {[...project.layers].reverse().map(layer => (
                      <div
                        key={layer.layer_id}
                        className={`flex items-center gap-1.5 rounded px-2 py-1.5 cursor-pointer text-xs transition-colors ${selectedId === layer.layer_id ? "bg-primary/10 text-primary" : "hover:bg-muted/50"}`}
                        onClick={() => { setSelectedId(layer.layer_id); if (editingTextId) commitTextEdit() }}
                      >
                        {layer.type === "image" ? <ImageIcon className="h-3 w-3 shrink-0" /> : <Type className="h-3 w-3 shrink-0" />}
                        <span className="flex-1 truncate">{layer.type === "text" ? (layer.text?.substring(0,14) || "Text") : "Image"}</span>
                        <button className="opacity-60 hover:opacity-100 h-5 w-5 flex items-center justify-center"
                          onClick={e => { e.stopPropagation(); updateLayer(layer.layer_id, { visible: layer.visible === false ? true : false }) }}>
                          {layer.visible === false ? <EyeOff className="h-2.5 w-2.5" /> : <Eye className="h-2.5 w-2.5" />}
                        </button>
                      </div>
                    ))}
                  </div>
                </ScrollArea>
              </div>
            )}
          </div>
        </div>
      </div>
    </>
  )
}

export default function EditorPage() {
  return (
    <Suspense fallback={<div className="flex h-full items-center justify-center"><RefreshCw className="h-8 w-8 animate-spin text-primary" /></div>}>
      <EditorInner />
    </Suspense>
  )
}
